-- @gate: add
-- Depends on 107
-- ============================================================================
-- 1102_workspace_alias_unified.sql — core.workspace_alias_unified: ONE alias table
-- across all 4 workspace identifier spaces (warehouse slug, Instantly UUID,
-- king-slug, display names incl. stale codenames), for consumers that today juggle
-- core.workspace_alias / core.workspace_slug_alias / core.v_instantly_workspace_crosswalk.
--
-- SOURCE: deliverables/2026-07-14-cold-email-bi/workspace-alias-map.csv (Sam-validated
-- 2026-07-14; live names API-verified same day). Sam rulings ENCODED:
--   * renaissance-8 -> status_class='deleted_no_data' (history permanently gone).
--   * section-125   -> no API key BY DESIGN (notes).
--   * tariffs       -> key INSTANTLY_KEY_TARIFFS filed 07-14 (notes); out of funding scope.
--   * growth-1      -> new team ws 07-14; offer TBD; no key yet (notes).
--   * (my-organization) -> empty_default, assumed_empty.
-- SUPERSEDES-IN-CONCEPT (not dropped; consumers migrate one at a time): the partial
-- core.workspace_alias (col-O labels) / core.workspace_slug_alias / crosswalk trio.
-- NEVER read raw_pipeline_campaigns.workspace_name (stale codenames — standing rule);
-- resolve any identifier through this table instead.
--
-- Idempotent: ON CONFLICT (alias, alias_kind) DO NOTHING. Additive only. Reversible:
-- DROP TABLE core.workspace_alias_unified + DROP VIEW core.v_workspace_slug_norm.
-- ============================================================================

CREATE SCHEMA IF NOT EXISTS core;

CREATE TABLE IF NOT EXISTS core.workspace_alias_unified (
  alias                  VARCHAR NOT NULL,   -- the identifier as it appears in data
  alias_kind             VARCHAR NOT NULL,   -- warehouse_slug|uuid|king_slug|display_name|stale_codename
  warehouse_slug         VARCHAR NOT NULL,   -- canonical key of the map
  instantly_workspace_id VARCHAR,            -- Instantly org UUID where known
  status_class           VARCHAR NOT NULL,   -- live|deleted|deleted_no_data|empty_default|sms|whatsapp|unknown
  status_raw             VARCHAR,            -- verbatim status from the validated map
  funding_relevant       VARCHAR NOT NULL,   -- y|n|mixed|unknown
  owner_cm               VARCHAR,            -- workspace-credited CM lineage (slash-joined eras)
  notes                  VARCHAR,
  PRIMARY KEY (alias, alias_kind)
);

