-- Case-insensitive any-identifier -> canonical slug resolver (one row per distinct
-- lowercased alias; ambiguous aliases resolved by kind priority: slug > uuid > king >
-- display > stale).
CREATE OR REPLACE VIEW core.v_workspace_slug_norm AS
SELECT alias_lower, warehouse_slug, alias_kind, status_class, funding_relevant
FROM (
  SELECT lower(alias) AS alias_lower, warehouse_slug, alias_kind, status_class, funding_relevant,
         row_number() OVER (
           PARTITION BY lower(alias)
           ORDER BY CASE alias_kind
             WHEN 'warehouse_slug' THEN 1 WHEN 'uuid' THEN 2 WHEN 'king_slug' THEN 3
             WHEN 'display_name' THEN 4 ELSE 5 END
         ) AS rn
  FROM core.workspace_alias_unified
) t
WHERE rn = 1;
